const order = $input.first().json;

let items = [];
try {
  items = typeof order.items === 'string' ? JSON.parse(order.items) : (order.items || []);
} catch(e) {}

// Describe what they ordered in plain English
let itemDesc = '';
if (items.length > 0) {
  itemDesc = items.map(i => {
    const qty = (i.quantity && i.quantity > 1) ? i.quantity + 'x ' : '';
    return qty + (i.name || 'item');
  }).join(', ');
}

// Include service specs if present
const notes = (order.customer_notes || '').trim();
const isBooking = order.delivery_type === 'appointment';
const orderType = isBooking ? 'booking' : 'order';

// Time of day greeting (Lagos WAT = UTC+1)
const lagosHour = new Date(new Date().getTime() + 60 * 60 * 1000).getUTCHours();
let greeting = 'Good morning';
if (lagosHour >= 12 && lagosHour < 17) greeting = 'Good afternoon';
else if (lagosHour >= 17) greeting = 'Good evening';

// Parse tone
let tone = 'friendly and warm';
try {
  const tp = typeof order.tone_profile === 'string' ? JSON.parse(order.tone_profile) : (order.tone_profile || {});
  tone = tp.tone_summary || 'friendly and warm';
} catch(e) {}

const customerName = (order.customer_name || 'there').split(' ')[0]; // first name only

const prompt = `You are ${order.agent_name}, the AI assistant for ${order.business_name}.

Write a SHORT, natural follow-up message to a customer named ${customerName}.
They ${isBooking ? 'booked a service' : 'started an order'} but went quiet before completing it.

WHAT THEY ORDERED: ${itemDesc || 'an item from table_6 catalogue'}${notes ? '\nTheir specs: ' + notes : ''}

TIME OF DAY: ${greeting} (Lagos time)
TONE: ${tone}

RULES — read carefully:
- Start with: "${greeting} ${customerName}!"
- Sound like a HUMAN casually checking in — NOT an automated reminder
- Reference their specific ${isBooking ? 'booking' : 'order'} naturally (mention what they wanted)
- NEVER say: "pending order", "complete your purchase", "you have an outstanding", "reminder"
- Frame it as genuine care: you noticed, you wanted to check they're okay, you're happy to help
- 2-3 sentences MAXIMUM. Keep it short and warm.
- End with something that invites a low-pressure reply (not a direct call to action)
- No emojis except one at the end if appropriate
- Telegram plain text only — no markdown

EXAMPLE (do not copy — generate something original):
"Good morning Ada! Just wanted to check in — are you still thinking about the senator suit? No rush at all, happy to pick up where we left off whenever works for you 😊"

Generate the message now. Output ONLY the message text, nothing else.`;

return {
  json: {
    order_id:      order.order_id,
    order_number:  order.order_number,
    customer_chat_id: String(order.customer_chat_id),
    bot_token:     order.bot_token,
    business_name: order.business_name,
    agent_name:    order.agent_name,
    customer_name: customerName,
    item_desc:     itemDesc,
    prompt
  }
};

