const prev = $('Build Follow-Up Prompt').first().json;
const groqResponse = $input.first().json;

let message = '';
try {
  message = groqResponse.choices[0].message.content.trim();
} catch(e) {
  // Safe fallback — still references their order specifically
  message = 'Good morning ' + prev.customer_name + '! Just checking in about ' +
    (prev.item_desc || 'your recent enquiry') + ' — happy to help whenever you\'re ready 😊';
}

// Strip any quotes Groq may have wrapped it in
message = message.replace(/^"|"$/g, '').trim();

return {
  json: {
    order_id:         prev.order_id,
    order_number:     prev.order_number,
    customer_chat_id: prev.customer_chat_id,
    bot_token:        prev.bot_token,
    message
  }
};
